// Baseline Conventional Commits with relaxed line-length for Korean text
// and machine-generated trailers (Co-Authored-By, etc.). Add a scope-enum
// entry to enforce a closed list of scopes for your repo.
module.exports = {
  extends: ['@commitlint/config-conventional'],
  rules: {
    'subject-case': [0],
    'header-max-length': [2, 'always', 100],
    'body-max-line-length': [0],
    'footer-max-line-length': [0]
    // 'scope-enum': [2, 'always', ['api', 'web', 'docs']]
  }
};
